import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { MatCardModule } from '@angular/material/card';
import { MatTableModule } from '@angular/material/table';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { MatDialog } from '@angular/material/dialog';
import { MatTableDataSource } from '@angular/material/table';
import { RoomsService, Habitacion } from '../../services/rooms.service';
import { RoomCreateDialogComponent } from './room-create-dialog.component';
import { RoomDeleteConfirmDialogComponent, RoomDeleteConfirmData } from './room-delete-confirm-dialog.component';

@Component({
  selector: 'app-habitaciones',
  standalone: true,
  imports: [
    CommonModule,
    MatCardModule,
    MatTableModule,
    MatButtonModule,
    MatIconModule,
    MatProgressSpinnerModule,
  ],
  templateUrl: './habitaciones.component.html',
  styleUrl: './habitaciones.component.scss',
})
export class HabitacionesComponent implements OnInit {
  loading = false;
  errorMessage = '';

  dataSource = new MatTableDataSource<Habitacion>([]);
  displayedColumns: string[] = [
    'numeroHabitacion',
    'tipoHabitacion',
    'capacidad',
    'precioPorNoche',
    'estado',
    'descripcion',
    'acciones',
  ];

  constructor(
    private dialog: MatDialog,
    private roomsService: RoomsService
  ) {}

  ngOnInit(): void {
    this.loadRooms();
  }

  private loadRooms(): void {
    this.loading = true;
    this.errorMessage = '';

    this.roomsService.getRooms().subscribe({
      next: (rooms) => {
        this.dataSource.data = rooms;
        this.loading = false;
      },
      error: (err) => {
        this.loading = false;
        this.errorMessage =
          err?.error?.message ?? 'No se pudieron cargar las habitaciones.';
      },
    });
  }

  estadoLabel(estado: number): string {
    switch (estado) {
      case 0:
        return 'Disponible';
      case 1:
        return 'Ocupado';
      case 2:
        return 'En mantenimiento';
      case 3:
        return 'Reservado';
      default:
        return String(estado);
    }
  }

  openCreateDialog(): void {
    const dialogRef = this.dialog.open(RoomCreateDialogComponent, {
      width: '720px',
      disableClose: true,
    });

    dialogRef.afterClosed().subscribe((res) => {
      if (res) this.loadRooms();
    });
  }

  openEditDialog(room: Habitacion): void {
    const dialogRef = this.dialog.open(RoomCreateDialogComponent, {
      width: '720px',
      disableClose: true,
      data: { room },
    });

    dialogRef.afterClosed().subscribe((res) => {
      if (res) this.loadRooms();
    });
  }

  openDeleteConfirmDialog(room: Habitacion): void {
    const data: RoomDeleteConfirmData = {
      title: 'Eliminar habitación',
      message: '¿Está seguro de que desea eliminar esta habitación?',
      roomNumber: room.numeroHabitacion,
    };

    const dialogRef = this.dialog.open(RoomDeleteConfirmDialogComponent, {
      width: '400px',
      data,
    });

    dialogRef.afterClosed().subscribe((confirmed) => {
      if (confirmed) {
        this.roomsService.deleteRoom(room.idHabitacion).subscribe({
          next: () => this.loadRooms(),
          error: (err) => {
            this.errorMessage =
              err?.error?.message ?? err?.message ?? 'No se pudo eliminar la habitación.';
          },
        });
      }
    });
  }
}
<mat-card class="rooms-card">
  <mat-card-header>
    <mat-card-title>Gestión de habitaciones</mat-card-title>
    <mat-card-subtitle>Listado de habitaciones y creación nueva</mat-card-subtitle>
  </mat-card-header>

  <mat-card-content>
    <div class="toolbar">
      <button mat-flat-button color="primary" (click)="openCreateDialog()">
        <mat-icon>add</mat-icon>
        Crear habitación
      </button>
    </div>

    <p class="error-msg" *ngIf="errorMessage">{{ errorMessage }}</p>

    <div class="loading" *ngIf="loading">
      <mat-spinner diameter="40"></mat-spinner>
    </div>

    <div class="table-wrapper" *ngIf="!loading && dataSource.data.length > 0">
      <table mat-table [dataSource]="dataSource" class="mat-elevation-z1">
        <ng-container matColumnDef="numeroHabitacion">
          <th mat-header-cell *matHeaderCellDef>Número</th>
          <td mat-cell *matCellDef="let row">{{ row.numeroHabitacion }}</td>
        </ng-container>

        <ng-container matColumnDef="tipoHabitacion">
          <th mat-header-cell *matHeaderCellDef>Tipo</th>
          <td mat-cell *matCellDef="let row">{{ row.tipoHabitacion }}</td>
        </ng-container>

        <ng-container matColumnDef="capacidad">
          <th mat-header-cell *matHeaderCellDef>Capacidad</th>
          <td mat-cell *matCellDef="let row">{{ row.capacidad }}</td>
        </ng-container>

        <ng-container matColumnDef="precioPorNoche">
          <th mat-header-cell *matHeaderCellDef>Precio/Noche</th>
          <td mat-cell *matCellDef="let row">{{ row.precioPorNoche }}</td>
        </ng-container>

        <ng-container matColumnDef="estado">
          <th mat-header-cell *matHeaderCellDef>Estado</th>
          <td mat-cell *matCellDef="let row">{{ estadoLabel(row.estado) }}</td>
        </ng-container>

        <ng-container matColumnDef="descripcion">
          <th mat-header-cell *matHeaderCellDef>Descripción</th>
          <td mat-cell *matCellDef="let row">{{ row.descripcion }}</td>
        </ng-container>

        <ng-container matColumnDef="acciones">
          <th mat-header-cell *matHeaderCellDef>Acciones</th>
          <td mat-cell *matCellDef="let row">
            <button mat-icon-button (click)="openEditDialog(row)" matTooltip="Editar" type="button">
              <mat-icon>edit</mat-icon>
            </button>
            <button mat-icon-button (click)="openDeleteConfirmDialog(row)" matTooltip="Eliminar" type="button" color="warn">
              <mat-icon>close</mat-icon>
            </button>
          </td>
        </ng-container>

        <tr mat-header-row *matHeaderRowDef="displayedColumns"></tr>
        <tr mat-row *matRowDef="let row; columns: displayedColumns"></tr>
      </table>
    </div>

    <p class="empty-msg" *ngIf="!loading && dataSource.data.length === 0">
      No hay habitaciones registradas.
    </p>
  </mat-card-content>
</mat-card>
